from instructor import from_openai

from openai import OpenAI

client = from_openai(OpenAI())

@client.chat.completions.create
async def rag_extract(
    context: str,
    question: str
) -> RAGResponse:
    return await client.chat.completions.create(
        model="gpt-4o",
        response_model=RAGResponse,
        temperature=0.1,
        messages=[
            {"role": "system", "content": "Answer using ONLY the provided context. Always cite sources."},
            {"role": "user", "content": f"Context: {context}\n\nQuestion: {question}"}
        ]
    )

import { z } from 'zod';

const CitationSchema = z.object({
  chunkId: z.number(),
  startChar: z.number(),
  endChar: z.number(),
  content: z.string().max(500)
});

const RAGResponseSchema = z.object({
  answer: z.string().max(1000),
  citations: z.array(CitationSchema).min(1).max(5),
  confidence: z.number().min(0).max(1),
  sourcesUsed: z.number().min(1)
});

export type RAGResponse = z.infer<typeof RAGResponseSchema>;

